<?php
namespace App\Domain\Characters\Appearance;use App\Domain\Equipment\EquipmentType;use App\Domain\Equipment\HandItemConfigurationValidator;use App\Domain\Equipment\HandRequirement;use App\Models\Item;use InvalidArgumentException;
final class ItemVisualSlotResolver{private $hands;public function __construct(HandItemConfigurationValidator $hands){$this->hands=$hands;}public function allowedSlots(Item $item){if($item->item_type!=='equipment')return[];$map=[EquipmentType::NECKLACE=>['pendant'],EquipmentType::HELMET=>['helmet'],EquipmentType::GLOVES=>['gloves'],EquipmentType::BOOTS=>['boots'],EquipmentType::ARMOR=>['armor'],EquipmentType::RING=>['ring_left','ring_right']];if(isset($map[$item->equipment_type]))return$map[$item->equipment_type];if($item->equipment_type!==EquipmentType::WEAPON)return[];$kind=$this->hands->classify($item);if($kind===HandRequirement::ONE_HAND)return['main_hand','off_hand'];if($kind===HandRequirement::OFF_HAND_ONLY)return['off_hand'];return['main_hand'];}public function assertAllowed(Item $item,$slot){if(!in_array($slot,$this->allowedSlots($item),true))throw new InvalidArgumentException('El canal visual no es compatible con este objeto.');return$slot;}public function visualSlotForEquipmentSlot($slot){return$slot==='necklace'?'pendant':$slot;}}
